#!/usr/bin/env python3 import asyncio import aiohttp from typing import Dict, List, Any
async def fetch_url(session: aiohttp.ClientSession, url: str) -> Dict[str, Any]: async with session.get(url) as response: return await response.json()
async def main(): urls = [ "https://api.example.com/users", "https://api.example.com/posts", "https://api.example.com/comments" ]
async with aiohttp.ClientSession() as session: tasks = [fetch_url(session, url) for url in urls] results = await asyncio.gather(*tasks)
for result in results: print(f"Fetched {len(result)} items")
if __name__ == "__main__": asyncio.run(main())

